def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        base_dir = os.path.realpath(dir_path)
        target_path = os.path.realpath(os.path.join(base_dir, filename))
        if os.path.commonpath([base_dir, target_path]) != base_dir:
            return ""
        with open(target_path, "r", encoding="utf-8", errors="replace") as f:
            return f.read()
    except Exception:
        return ""

import os
import tarfile


def extract_tar_to_path(tar_path, dest_path) -> bool:
    def _is_within(base: str, target: str) -> bool:
        try:
            return os.path.commonpath([base, target]) == base
        except ValueError:
            return False

    try:
        dest_abs = os.path.realpath(os.path.abspath(dest_path))
        os.makedirs(dest_abs, exist_ok=True)

        with tarfile.open(tar_path, 'r:*') as tar:
            if hasattr(tar, 'extraction_filter'):
                tar.extraction_filter = lambda member, path: member

            for member in tar.getmembers():
                member_path = os.path.realpath(os.path.join(dest_abs, member.name))
                if not _is_within(dest_abs, member_path):
                    return False

                if member.issym() or member.islnk():
                    linkname = member.linkname
                    if linkname.startswith('/') or os.path.isabs(linkname):
                        link_target = os.path.realpath(linkname)
                    else:
                        link_target = os.path.realpath(
                            os.path.join(os.path.dirname(member_path), linkname)
                        )
                    if not _is_within(dest_abs, link_target):
                        return False

                tar.extract(member, dest_abs)
        return True
    except Exception:
        return False

import ast
import operator

def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    if not isinstance(expr, str):
        return ''

    try:
        tree = ast.parse(expr, mode='eval')
    except Exception:
        return ''

    bin_ops = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
    }

    unary_ops = {
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
    }

    def _eval(node):
        if isinstance(node, ast.Expression):
            return _eval(node.body)

        if isinstance(node, ast.Constant):
            if isinstance(node.value, bool) or not isinstance(node.value, (int, float)):
                raise ValueError('Disallowed constant')
            return node.value

        num_cls = getattr(ast, 'Num', None)
        if num_cls is not None and isinstance(node, num_cls):
            if isinstance(node.n, bool) or not isinstance(node.n, (int, float)):
                raise ValueError('Disallowed number')
            return node.n

        if isinstance(node, ast.BinOp):
            left = _eval(node.left)
            right = _eval(node.right)
            op = bin_ops.get(type(node.op))
            if op is None:
                raise ValueError('Disallowed binary operator')
            return op(left, right)

        if isinstance(node, ast.UnaryOp):
            operand = _eval(node.operand)
            op = unary_ops.get(type(node.op))
            if op is None:
                raise ValueError('Disallowed unary operator')
            return op(operand)

        raise ValueError('Disallowed expression')

    try:
        result = _eval(tree)
        if isinstance(result, bool) or not isinstance(result, (int, float)):
            raise ValueError('Disallowed result type')
        return str(result)
    except Exception:
        return ''

from typing import Dict


def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    type_to_header = {
        "lang": "Accept-Language",
        "encoding": "Accept-Encoding",
        "cache": "Cache-Control",
    }

    if info_type not in type_to_header:
        return header

    if not isinstance(info_content, str) or not isinstance(header, dict):
        return header

    if any(
        c in "\r\n\0" or (ord(c) < 32 and c not in " \t") or ord(c) > 126
        for c in info_content
    ):
        return header

    new_header = dict(header)
    new_header[type_to_header[info_type]] = info_content
    return new_header

