from lxml import etree


def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    try:
        parser = etree.XMLParser(resolve_entities=False, no_network=True)
        root = etree.fromstring(xml_data.encode("utf-8"), parser=parser)
    except etree.XMLSyntaxError:
        return None

    students = root.xpath(
        "//student[username=$user and password=$pwd]",
        user=username,
        pwd=password,
    )
    if not students:
        return None

    student = students[0]
    result: Dict[str, str] = {}
    for child in student:
        tag = etree.QName(child).localname
        if tag not in ("username", "password"):
            result[tag] = child.text or ""
    return result

import re

def get_url_for_query(api_url: str, user_id: str) -> str | None:
    if not isinstance(api_url, str) or not isinstance(user_id, str):
        return None

    user_id = user_id.strip()
    if not user_id or not re.fullmatch(r"[A-Za-z0-9_-]+", user_id):
        return None

    return f"{api_url.rstrip('/')}/{user_id}"

