import subprocess
import shlex

FORBIDDEN = ";|&`$(){}[]<>!\\\n\\\r"

def executeCommand() -> int:
    command = input().strip()
    if not command:
        raise ValueError("No command provided")
    if any(c in FORBIDDEN for c in command):
        raise ValueError("Invalid command: shell metacharacters are not allowed")
    try:
        args = shlex.split(command)
    except ValueError as exc:
        raise ValueError("Invalid command syntax") from exc
    if not args:
        raise ValueError("No command provided")
    result = subprocess.run(args, shell=False)
    return result.returncode

